class Graph:
    def __init__(self):
        self.adj_list = {}

    def add_vertex(self, vertex):
        if vertex not in self.adj_list:
            self.adj_list[vertex] = []
            return True
        return False

    def add_edge(self, v1, v2, is_directed=False):
        if v1 in self.adj_list and v2 in self.adj_list:
            if v2 not in self.adj_list[v1]:
                self.adj_list[v1].append(v2)
            if not is_directed and v1 not in self.adj_list[v2]:
                self.adj_list[v2].append(v1)
            return True
        return False

    def remove_edge(self, v1, v2, is_directed=False):
        if v1 in self.adj_list and v2 in self.adj_list:
            try:
                self.adj_list[v1].remove(v2)
            except ValueError:
                pass # Edge might not exist
            if not is_directed:
                try:
                    self.adj_list[v2].remove(v1)
                except ValueError:
                    pass # Edge might not exist
            return True
        return False

    def remove_vertex(self, vertex):
        if vertex in self.adj_list:
            # Remove all edges pointing to this vertex
            for other_vertex in list(self.adj_list.keys()):
                if vertex in self.adj_list[other_vertex]:
                    self.adj_list[other_vertex].remove(vertex)
            # Remove the vertex itself
            del self.adj_list[vertex]
            return True
        return False

    def print_graph(self):
        for vertex, neighbors in self.adj_list.items():
            print(f"{vertex}: {neighbors}")

if __name__ == "__main__":
    my_graph = Graph()

    my_graph.add_vertex("A")
